const seen = new Set();

return items
  .map(item => {
    const track = item.json.track;
    return {
      json: {
        trackName: track.name,
        artistName: track.artists[0].name,
        spotifyUrl: track.external_urls?.spotify || ''
      }
    };
  })
  .filter(item => {
    const key = item.json.spotifyUrl;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });

const lyricsData = $('Put all Lyrics together').first().json;

const existingWords = items
  .map(item => item.json.Word)
  .filter(w => w);

return [{
  json: {
    allLyrics: lyricsData.allLyrics,
    songCount: lyricsData.songCount,
    existingWords: existingWords
  }
}];

return items.map(item => ({
  json: {
    Word: item.json.Word,
    Translation: item.json.Translation
  }
}));

// 1. Parse AI Output
const results = [];
for (const item of items) {
  const output = item.json.output || '';
  const clean = output.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  try {
    const words = JSON.parse(clean);
    for (const word of words) {
      results.push({
        Word: word.word,
        Translation: word.translation.replace(/\s*\(.*?\)\s*$/, '')
      });
    }
  } catch (e) {
    console.log('Parse Error:', e.message);
    console.log('Raw output:', output);
  }
}

// 2. Deduplicate
const existingWords = $('Combine existing Words with new Words')
  .first()
  .json
  .existingWords
  .map(w => String(w || '').toLowerCase().trim());


const unique = results.filter(r =>
  !existingWords.includes(r.Word.toLowerCase().trim())
);

// 3. Week Number
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNumber = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const sheetName = `Week ${weekNumber}`;

return unique.map(word => ({
  json: {
    Word: word.Word,
    Translation: word.Translation,
    sheetName: sheetName
  }
}));

const songs = {};

for (const item of items) {
  const data = item.json;

  let cleanTrack = (data.trackName || '')
    .replace(/\s*[\(\[].*?[\)\]]/g, '')
    .replace(/^.*?\s*-\s*"?/, '')
    .replace(/['"\\]/g, '')
    .trim()
    .toLowerCase();

  let cleanArtist = (data.artistName || '')
    .replace(/\s*-\s*Topic$/i, '')
    .trim()
    .toLowerCase();

  const key = cleanArtist + ' - ' + cleanTrack;
  const lyrics = data.plainLyrics || '';

  if (!songs[key] || lyrics.length > songs[key].plainLyrics.length) {
    songs[key] = {
      trackName: data.trackName || '',
      artistName: cleanArtist,
      plainLyrics: lyrics.replace(/[\n\r]+/g, ' ').replace(/"/g, '\\"')
    };
  }
}

let allLyrics = '';
const uniqueSongs = Object.values(songs).filter(song => song.plainLyrics.length > 0);

for (const song of uniqueSongs) {
  allLyrics += `\n\n--- ${song.trackName} by ${song.artistName} ---\n${song.plainLyrics}`;
}

return [{
  json: {
    allLyrics: allLyrics.trim(),
    songCount: uniqueSongs.length
  }
}];
